import{_ as a,o as n,c as i,ag as t}from"./chunks/framework.Dcoxob_B.js";const h=JSON.parse('{"title":"Roadmap","description":"","frontmatter":{"_rawMarkdown":"# Roadmap\\n\\nThis document outlines the development roadmap for OpenViking.\\n\\n## Completed Features\\n\\n### Core Infrastructure\\n- Three-layer information model (L0/L1/L2)\\n- Viking URI addressing system\\n- Dual-layer storage (AGFS + Vector Index)\\n- Async/Sync client support\\n\\n### Resource Management\\n- Text resource management (Markdown, HTML, PDF)\\n- Automatic L0/L1 generation\\n- Semantic search with vector indexing\\n- Resource relations and linking\\n\\n### Retrieval\\n- Basic semantic search (`find`)\\n- Context-aware search with intent analysis (`search`)\\n- Session-based query expansion\\n- Reranking pipeline\\n\\n### Session Management\\n- Conversation state tracking\\n- Context and skill usage tracking\\n- Automatic memory extraction\\n- Memory deduplication with LLM\\n- Session archiving and compression\\n\\n### Skills\\n- Skill definition and storage\\n- MCP tool auto-conversion\\n- Skill search and retrieval\\n\\n### Configuration\\n- Pluggable embedding providers\\n- Pluggable LLM providers\\n- YAML-based configuration\\n\\n### Server & Client Architecture\\n- HTTP Server (FastAPI)\\n- Python HTTP Client\\n- API Key authentication\\n- Client abstraction layer (LocalClient / HTTPClient)\\n\\n---\\n\\n## Future Plans\\n\\n### CLI\\n- Complete command-line interface for all operations\\n- Distributed storage backend\\n\\n### Multi-modal Support\\n- Intelligent parsing and access for multi-modal resources (images, video, audio, etc.)\\n- Directory storage structure for multi-modal resources\\n\\n### Context Management\\n- Propagation updates when context is modified\\n- Version management and rollback for context (git-like)\\n\\n### Resource Node Access Control\\n- Multi-Agent / Multi-User support\\n- Role-based isolation design\\n- Access control and permission design for resource directory nodes\\n\\n### Ecosystem Integration\\n- Popular Agent framework adapters\\n- Plugin system for custom components\\n\\nWe welcome suggestions and feedback in issues.\\n\\n---\\n\\n## Contributing\\n\\nWe welcome contributions to help achieve these goals. See [Contributing](contributing.md) for guidelines.\\n"},"headers":[],"relativePath":"en/about/03-roadmap.md","filePath":"en/about/03-roadmap.md","lastUpdated":1770642735000}'),o={name:"en/about/03-roadmap.md"};function r(l,e,s,c,u,d){return n(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p>This document outlines the development roadmap for OpenViking.</p><h2 id="completed-features" tabindex="-1">Completed Features <a class="header-anchor" href="#completed-features" aria-label="Permalink to &quot;Completed Features&quot;">​</a></h2><h3 id="core-infrastructure" tabindex="-1">Core Infrastructure <a class="header-anchor" href="#core-infrastructure" aria-label="Permalink to &quot;Core Infrastructure&quot;">​</a></h3><ul><li>Three-layer information model (L0/L1/L2)</li><li>Viking URI addressing system</li><li>Dual-layer storage (AGFS + Vector Index)</li><li>Async/Sync client support</li></ul><h3 id="resource-management" tabindex="-1">Resource Management <a class="header-anchor" href="#resource-management" aria-label="Permalink to &quot;Resource Management&quot;">​</a></h3><ul><li>Text resource management (Markdown, HTML, PDF)</li><li>Automatic L0/L1 generation</li><li>Semantic search with vector indexing</li><li>Resource relations and linking</li></ul><h3 id="retrieval" tabindex="-1">Retrieval <a class="header-anchor" href="#retrieval" aria-label="Permalink to &quot;Retrieval&quot;">​</a></h3><ul><li>Basic semantic search (<code>find</code>)</li><li>Context-aware search with intent analysis (<code>search</code>)</li><li>Session-based query expansion</li><li>Reranking pipeline</li></ul><h3 id="session-management" tabindex="-1">Session Management <a class="header-anchor" href="#session-management" aria-label="Permalink to &quot;Session Management&quot;">​</a></h3><ul><li>Conversation state tracking</li><li>Context and skill usage tracking</li><li>Automatic memory extraction</li><li>Memory deduplication with LLM</li><li>Session archiving and compression</li></ul><h3 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;Skills&quot;">​</a></h3><ul><li>Skill definition and storage</li><li>MCP tool auto-conversion</li><li>Skill search and retrieval</li></ul><h3 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h3><ul><li>Pluggable embedding providers</li><li>Pluggable LLM providers</li><li>YAML-based configuration</li></ul><h3 id="server-client-architecture" tabindex="-1">Server &amp; Client Architecture <a class="header-anchor" href="#server-client-architecture" aria-label="Permalink to &quot;Server &amp; Client Architecture&quot;">​</a></h3><ul><li>HTTP Server (FastAPI)</li><li>Python HTTP Client</li><li>API Key authentication</li><li>Client abstraction layer (LocalClient / HTTPClient)</li></ul><hr><h2 id="future-plans" tabindex="-1">Future Plans <a class="header-anchor" href="#future-plans" aria-label="Permalink to &quot;Future Plans&quot;">​</a></h2><h3 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to &quot;CLI&quot;">​</a></h3><ul><li>Complete command-line interface for all operations</li><li>Distributed storage backend</li></ul><h3 id="multi-modal-support" tabindex="-1">Multi-modal Support <a class="header-anchor" href="#multi-modal-support" aria-label="Permalink to &quot;Multi-modal Support&quot;">​</a></h3><ul><li>Intelligent parsing and access for multi-modal resources (images, video, audio, etc.)</li><li>Directory storage structure for multi-modal resources</li></ul><h3 id="context-management" tabindex="-1">Context Management <a class="header-anchor" href="#context-management" aria-label="Permalink to &quot;Context Management&quot;">​</a></h3><ul><li>Propagation updates when context is modified</li><li>Version management and rollback for context (git-like)</li></ul><h3 id="resource-node-access-control" tabindex="-1">Resource Node Access Control <a class="header-anchor" href="#resource-node-access-control" aria-label="Permalink to &quot;Resource Node Access Control&quot;">​</a></h3><ul><li>Multi-Agent / Multi-User support</li><li>Role-based isolation design</li><li>Access control and permission design for resource directory nodes</li></ul><h3 id="ecosystem-integration" tabindex="-1">Ecosystem Integration <a class="header-anchor" href="#ecosystem-integration" aria-label="Permalink to &quot;Ecosystem Integration&quot;">​</a></h3><ul><li>Popular Agent framework adapters</li><li>Plugin system for custom components</li></ul><p>We welcome suggestions and feedback in issues.</p><hr><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h2><p>We welcome contributions to help achieve these goals. See <a href="./contributing">Contributing</a> for guidelines.</p>',33)])])}const g=a(o,[["render",r]]);export{h as __pageData,g as default};
